39	// Artifacts is the resolver for the artifacts query.
40	// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
41	// for the given project. Documents come from the FEAT-007 doc graph; other
42	// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
43	func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string, sortKey *ArtifactSort, staleness *string, phase *string, prefix []string) (*ArtifactConnection, error) {
44		root := r.projectRoot(projectID)
45	
46		artifacts, err := collectArtifacts(root)
47		if err != nil {
48			return nil, fmt.Errorf("collecting artifacts: %w", err)
49		}
50	
51		// Apply mediaType filter (supports X/* wildcard suffix).
52		if mediaType != nil && *mediaType != "" {
53			mt := *mediaType
54			filtered := artifacts[:0]
55			if strings.HasSuffix(mt, "/*") {
56				prefix := strings.TrimSuffix(mt, "*") // keep trailing slash
57				for _, a := range artifacts {
58					if strings.HasPrefix(a.MediaType, prefix) {
59						filtered = append(filtered, a)
60					}
61				}
62			} else {
63				for _, a := range artifacts {
64					if a.MediaType == mt {
65						filtered = append(filtered, a)
66					}
67				}
68			}
69			artifacts = filtered
70		}
71	
72		// Apply staleness filter.
73		if staleness != nil && *staleness != "" {
74			st := *staleness
75			filtered := artifacts[:0]
76			for _, a := range artifacts {
77				if a.Staleness == st {
78					filtered = append(filtered, a)
79				}
80			}
81			artifacts = filtered
82		}
83	
84		// Apply phase filter: matches when path is under docs/helix/<phase>/
85		// where <phase> is either an exact match (e.g. "01-frame") or a numeric
86		// prefix (e.g. "01") matching docs/helix/01-*/.
87		if phase != nil && *phase != "" {
88			ph := *phase
89			filtered := artifacts[:0]
90			for _, a := range artifacts {
91				if matchesPhase(a.Path, ph) {
92					filtered = append(filtered, a)
93				}
94			}
95			artifacts = filtered
96		}
97	
98		// Apply prefix filter (multi-value OR over id-prefix segments,
99		// e.g. ADR, SD, FEAT, US, RSCH).
100		if len(prefix) > 0 {
101			set := make(map[string]struct{}, len(prefix))
102			for _, p := range prefix {
103				if p != "" {
104					set[strings.ToUpper(p)] = struct{}{}
105				}
106			}
107			if len(set) > 0 {
108				filtered := artifacts[:0]
109				for _, a := range artifacts {
110					if _, ok := set[idPrefixSegment(a.ID)]; ok {
111						filtered = append(filtered, a)
112					}
113				}
114				artifacts = filtered
115			}
116		}
117	
118		// Apply search filter across title and path.
119		if search != nil && *search != "" {
120			q := strings.ToLower(*search)
121			filtered := artifacts[:0]
122			for _, a := range artifacts {
123				if strings.Contains(strings.ToLower(a.Title), q) ||
124					strings.Contains(strings.ToLower(a.Path), q) {
125					filtered = append(filtered, a)
126				}
127			}
128			artifacts = filtered
129		}
130	
131		// Sort with (sortKey, id) tie-breaker for stable cursor pagination.
132		sortArtifacts(artifacts, sortKey)
133	
134		// Build Relay edges.
135		all := make([]*ArtifactEdge, len(artifacts))
136		for i, a := range artifacts {
137			cp := a
138			all[i] = &ArtifactEdge{
139				Node:   cp,
140				Cursor: encodeStableCursor(cp.ID),
141			}
142		}
143	
144		startIdx := 0
145		if after != nil {
146			if afterID, ok := decodeStableCursor(*after); ok {
147				for i, e := range all {
148					if e.Node.ID == afterID {
149						startIdx = i + 1
150						break
151					}
152				}
153			}
154		}
155		endIdx := len(all)
156		if before != nil {
157			if beforeID, ok := decodeStableCursor(*before); ok {
158				for i, e := range all {
159					if e.Node.ID == beforeID {
160						endIdx = i
161						break
162					}
163				}
164			}
165		}
166		if startIdx > endIdx {
167			startIdx = endIdx
168		}
169	
170		windowSize := endIdx - startIdx
171		slice := all[startIdx:endIdx]
172		if first != nil && *first >= 0 && *first < len(slice) {
173			slice = slice[:*first]
174		}
175		if last != nil && *last >= 0 && *last < len(slice) {
176			slice = slice[len(slice)-*last:]
177		}
178	
179		pageInfo := &PageInfo{
180			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
181			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
182		}
183		if len(slice) > 0 {
184			pageInfo.StartCursor = &slice[0].Cursor
185			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
186		}
187	
188		return &ArtifactConnection{
189			Edges:      slice,
190			PageInfo:   pageInfo,
191			TotalCount: len(all),
192		}, nil
193	}
