258	// idPrefixSegment extracts the leading prefix segment from an artifact ID.
259	// IDs are typically formatted as "doc:<PREFIX>-..." (e.g. "doc:ADR-001-foo")
260	// or "<PREFIX>-..." for sidecar artifacts. The "doc:" / "sidecar:" namespace
261	// prefix, if present, is stripped before extraction. Returns empty string
262	// when no prefix segment can be identified.
263	func idPrefixSegment(id string) string {
264		s := id
265		for _, ns := range []string{"doc:", "sidecar:"} {
266			if strings.HasPrefix(s, ns) {
267				s = s[len(ns):]
268				break
269			}
270		}
271		if i := strings.IndexByte(s, '-'); i > 0 {
272			return strings.ToUpper(s[:i])
273		}
274		return ""
275	}
