278	// artifact's frontmatter, or 0 if none / unparseable.
279	func dependsOnCount(a *Artifact) int {
280		if a.DdxFrontmatter == nil {
281			return 0
282		}
283		var fm map[string]interface{}
284		if err := json.Unmarshal([]byte(*a.DdxFrontmatter), &fm); err != nil {
285			return 0
286		}
287		deps, ok := fm["depends_on"].([]interface{})
288		if !ok {
289			return 0
290		}
291		return len(deps)
292	}
