294	// collectArtifacts gathers all DDx-tracked artifacts from two sources:
295	//  1. The doc graph (markdown documents under the project root).
296	//  2. .ddx.yaml sidecar files under .ddx/plugins/.
297	func collectArtifacts(root string) ([]*Artifact, error) {
298		var artifacts []*Artifact
299	
300		// 1. Documents from the doc graph.
301		if docs, err := collectDocArtifacts(root); err == nil {
302			artifacts = append(artifacts, docs...)
303		}
304	
305		// 2. Sidecar artifacts from .ddx/plugins/.
306		if sidecars, err := collectSidecarArtifacts(root); err == nil {
307			artifacts = append(artifacts, sidecars...)
308		}
309	
310		return artifacts, nil
311	}
