313	// collectDocArtifacts builds Artifact records from the FEAT-007 doc graph.
314	func collectDocArtifacts(root string) ([]*Artifact, error) {
315		graph, err := docgraph.BuildGraphWithConfig(root)
316		if err != nil {
317			return nil, err
318		}
319	
320		staleSet := map[string]string{} // id → staleness ("stale" or "missing")
321		for _, entry := range graph.StaleDocs() {
322			staleness := "stale"
323			for _, reason := range entry.Reasons {
324				if strings.Contains(reason, "missing dependency") ||
325					strings.Contains(reason, "missing review hash") {
326					staleness = "missing"
327					break
328				}
329			}
330			staleSet[entry.ID] = staleness
331		}
332	
333		docs := graph.AllNodesForOutput()
334		out := make([]*Artifact, 0, len(docs))
335		for _, d := range docs {
336			staleness := "fresh"
337			if s, ok := staleSet[d.ID]; ok {
338				staleness = s
339			}
340	
341			a := &Artifact{
342				ID:        "doc:" + d.ID,
343				Path:      d.Path,
344				Title:     titleFromDoc(d),
345				MediaType: "text/markdown",
346				Staleness: staleness,
347			}
348	
349			// Populate updatedAt from file mod time.
350			absPath := d.Path
351			if !filepath.IsAbs(absPath) {
352				absPath = filepath.Join(graph.RootDir, absPath)
353			}
354			if info, statErr := os.Stat(absPath); statErr == nil {
355				ts := info.ModTime().UTC().Format(time.RFC3339)
356				a.UpdatedAt = &ts
357			}
358	
359			// Populate ddxFrontmatter as a JSON summary of available metadata.
360			frontmatter := map[string]interface{}{
361				"id": d.ID,
362			}
363			if len(d.DependsOn) > 0 {
364				frontmatter["depends_on"] = d.DependsOn
365			}
366			if d.Prompt != "" {
367				frontmatter["prompt"] = d.Prompt
368			}
369			if fm, err := json.Marshal(frontmatter); err == nil {
370				s := string(fm)
371				a.DdxFrontmatter = &s
372			}
373	
374			out = append(out, a)
375		}
376		return out, nil
377	}
